// // This module performs a bitwise AND operation on three 9-bit inputs after shifting the second input left by 9 bits and the third input left by 18 bits.
module top_module(
    input [8:0] a,
    input [8:0] b,
    input [8:0] c,
    output reg [8:0] out
);always @(*) begin
        out = (a << 0) | (b << 9) | (c << 18);
    end

endmodule
